<old_str>static int blkoutstream_flush(FAR struct lib_blkoutstream_s *stream)
{
  FAR struct inode *inode = stream->inode;
  int ret = OK;

  /* Check if the stream or inode is valid */

  if (inode == NULL || stream->cache == NULL)
    {
      return -EIO;
    }

  /* Is there anything to flush? */

  if (stream->nbytes > 0)
    {
      /* Are we performing character-oriented I/O?  That is, are we
       * currently working with a block buffer?
       */

      if (stream->blpos != (off_t)-1)
        {
          /* Yes, flush the block buffer */

          ret = inode->u.i_bops->write(inode, stream->cache, stream->nbytes,
                                       stream->blpos);
          if (ret < 0)
            {
              goto errout;
            }

          /* Reset the buffer position and the number of bytes buffered */

          stream->blpos  = (off_t)-1;
          stream->nbytes = 0;
        }
      else
        {
          /* No, then we are performing block-oriented I/O */

          ret = inode->u.i_bops->write(inode, stream->cache, stream->nbytes,
                                       stream->offset);
          if (ret < 0)
            {
              goto errout;
            }

          /* Update the offset and reset the number of bytes buffered */

          stream->offset += stream->nbytes;
          stream->nbytes  = 0;
        }
    }

errout:
  return ret;
