<old_str>static int blkoutstream_seek(FAR struct lib_blkoutstream_s *stream,
                              off_t offset, int whence)
{
  FAR struct inode *inode = stream->inode;
  off_t newpos;
  int ret;

  /* Check if the stream or inode is valid */

  if (inode == NULL || stream->cache == NULL)
    {
      return -EIO;
    }

  /* Perform the flush as a side-effect of seeking */

  ret = blkoutstream_flush(stream);
  if (ret < 0)
    {
      return ret;
    }

  /* Then seek to the new position */

  switch (whence)
    {
      case SEEK_SET: /* The offset is set to offset bytes. */
        newpos = offset;
        break;

      case SEEK_CUR: /* The offset is set to its current location plus
                      * offset bytes. */
        newpos = stream->offset + offset;
        break;

      case SEEK_END: /* The offset is set to the size of the file plus
                      * offset bytes. */
        {
          newpos = inode->u.i_bops->geometry(inode, NULL);
          if (newpos < 0)
            {
              return (int)newpos;
            }

          newpos += offset;
        }
        break;

      default:
        return -EINVAL;
    }

  if (newpos < 0)
    {
      return -EINVAL;
    }

  stream->offset = newpos;
  return OK;
}</old_str>
