<old_str>static int blkoutstream_puts(FAR struct lib_blkoutstream_s *stream,
                              FAR const void *buf, int len)
{
  FAR struct inode *inode = stream->inode;
  FAR const char *ch = (FAR const char *)buf;
  FAR char *dest;
  int ret;
  int i;

  /* Check if the stream or inode is valid */

  if (inode == NULL || stream->cache == NULL)
    {
      return -EIO;
    }

  /* Handle the case where the first character to write is at the beginning
   * of the buffer.  In this case, we don't want to use the cache at all.
   */

  if (stream->nbytes == 0 && stream->blpos == (off_t)-1)
    {
      /* Flush the character immediately */

      ret = inode->u.i_bops->write(inode, ch, len, stream->offset);
      if (ret < 0)
        {
          return ret;
        }

      /* Update the offset */

      stream->offset += len;
      return len;
    }

  /* Add each character to the buffer one at a time */

  dest = stream->cache;
  for (i = 0; i < len; i++)
    {
      /* Add the next character to the buffer */

      dest[stream->nbytes++] = ch[i];

      /* If the buffer is full, flush it */

      if (stream->nbytes >= CONFIG_LIBC_BLKOUTSTREAM_BUFSIZE)
        {
          ret = blkoutstream_flush(stream);
          if (ret < 0)
            {
              return ret;
            }
        }
    }

  return len;
}</old_str>
